// MARK: - Crypto Utilities

class CryptoUtilities {
    static func generatePrivateKey() -> Data {
        var bytes = [UInt8](repeating: 0, count: 32)
        _ = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        return Data(bytes)
    }
    
    static func derivePublicKey(from privateKey: Data) -> Data {
        let curve = secp256k1()
        return curve.publicKey(from: privateKey)
    }
    
    static func sha256(_ data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
    
    static func ripemd160(_ data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_RIPEMD160_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_RIPEMD160($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
    
    static func base58Encode(_ data: Data) -> String {
        let alphabet = "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz"
        var bytes = [UInt8](data)
        var zerosCount = 0
        
        for byte in bytes {
            if byte != 0 { break }
            zerosCount += 1
        }
        
        bytes.removeFirst(zerosCount)
        
        var result = [Character]()
        var num = BigUInt(data)
        let base = BigUInt(58)
        
        while num > 0 {
            let remainder = num % base
            num = num / base
            let index = alphabet.index(alphabet.startIndex, offsetBy: Int(remainder.value))
            result.insert(alphabet[index], at: 0)
        }
        
        for _ in 0..<zerosCount {
            result.insert(alphabet.first!, at: 0)
        }
        
        return String(result)
    }
}

// MARK: - Big Unsigned Integer

struct BigUInt {
    var value: UInt64
    var data: Data
    
    init(_ value: UInt64) {
        self.value = value
        self.data = Data()
    }
    
    init(_ data: Data) {
        self.data = data
        var val: UInt64 = 0
        for byte in data {
            val = val * 256 + UInt64(byte)
        }
        self.value = val
    }
    
    static func >(lhs: BigUInt, rhs: Int) -> Bool {
        return lhs.value > UInt64(rhs)
    }
    
    static func %(lhs: BigUInt, rhs: BigUInt) -> BigUInt {
        return BigUInt(lhs.value % rhs.value)
    }
    
    static func /(lhs: BigUInt, rhs: BigUInt) -> BigUInt {
        return BigUInt(lhs.value / rhs.value)
    }
}

// MARK: - secp256k1 Implementation

class secp256k1 {
    func publicKey(from privateKey: Data) -> Data {
        let privateKeyBytes = [UInt8](privateKey)
        var publicKeyBytes = [UInt8](repeating: 0, count: 65)
        publicKeyBytes[0] = 0x04
        
        for i in 0..<32 {
            publicKeyBytes[i + 1] = privateKeyBytes[i]
            publicKeyBytes[i + 33] = privateKeyBytes[i]
        }
        
        return Data(publicKeyBytes)
    }
    
    func sign(message: Data, privateKey: Data) -> Data {
        let hash = CryptoUtilities.sha256(message)
        var signature = [UInt8](repeating: 0, count: 64)
        
        let hashBytes = [UInt8](hash)
        let keyBytes = [UInt8](privateKey)
        
        for i in 0..<32 {
            signature[i] = hashBytes[i] ^ keyBytes[i]
            signature[i + 32] = hashBytes[i] &+ keyBytes[i]
        }
        
        return Data(signature)
    }
}

// MARK: - Wallet Model

struct Wallet: Codable {
    let privateKey: Data
    let publicKey: Data
    let address: String
    
    init() {
        self.privateKey = CryptoUtilities.generatePrivateKey()
        self.publicKey = CryptoUtilities.derivePublicKey(from: privateKey)
        self.address = Wallet.generateAddress(from: publicKey)
    }
    
    static func generateAddress(from publicKey: Data) -> String {
        let sha256Hash = CryptoUtilities.sha256(publicKey)
        let ripemd160Hash = CryptoUtilities.ripemd160(sha256Hash)
        
        var addressData = Data([0x00])
        addressData.append(ripemd160Hash)
        
        let checksum = CryptoUtilities.sha256(CryptoUtilities.sha256(addressData))
        addressData.append(checksum.prefix(4))
        
        return CryptoUtilities.base58Encode(addressData)
    }
}

// MARK: - Transaction Model

struct Transaction: Codable {
    let from: String
    let to: String
    let amount: Double
    let timestamp: Date
    var signature: Data?
    
    func serialize() -> Data {
        let string = "\(from)\(to)\(amount)\(timestamp.timeIntervalSince1970)"
        return string.data(using: .utf8) ?? Data()
    }
    
    mutating func sign(with privateKey: Data) {
        let message = serialize()
        let curve = secp256k1()
        self.signature = curve.sign(message: message, privateKey: privateKey)
    }
}

// MARK: - Keychain Manager

class KeychainManager {
    static let shared = KeychainManager()
    
    private let service = "com.cryptowallet.keys"
    
    func saveWallet(_ wallet: Wallet) -> Bool {
        guard let data = try? JSONEncoder().encode(wallet) else { return false }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: "main_wallet",
            kSecValueData as String: data
        ]
        
        SecItemDelete(query as CFDictionary)
        
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func loadWallet() -> Wallet? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: "main_wallet",
            kSecReturnData as String: true
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess,
              let data = result as? Data,
              let wallet = try? JSONDecoder().decode(Wallet.self, from: data) else {
            return nil
        }
        
        return wallet
    }
    
    func deleteWallet() -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: "main_wallet"
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess
    }
}

// MARK: - Blockchain Service

class BlockchainService {
    static let shared = BlockchainService()
    
    private let baseURL = "https://api.blockchain.info"
    
    func getBalance(for address: String, completion: @escaping (Result<Double, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/balance?active=\(address)") else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1, userInfo: nil)))
            return
        }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let balances = json[address] as? [String: Any],
                  let finalBalance = balances["final_balance"] as? Int else {
                completion(.failure(NSError(domain: "Invalid response", code: -1, userInfo: nil)))
                return
            }
            
            let balance = Double(finalBalance) / 100000000.0
            completion(.success(balance))
        }.resume()
    }
    
    func broadcastTransaction(_ transaction: Transaction, completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/pushtx") else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1, userInfo: nil)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        
        let txData = transaction.serialize()
        let txHex = txData.map { String(format: "%02x", $0) }.joined()
        
        let body = "tx=\(txHex)"
        request.httpBody = body.data(using: .utf8)
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let responseString = String(data: data, encoding: .utf8) else {
                completion(.failure(NSError(domain: "Invalid response", code: -1, userInfo: nil)))
                return
            }
            
            completion(.success(responseString))
        }.resume()
    }
    
    func getTransactionHistory(for address: String, completion: @escaping (Result<[Transaction], Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/rawaddr/\(address)") else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1, userInfo: nil)))
            return
        }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let txs = json["txs"] as? [[String: Any]] else {
                completion(.failure(NSError(domain: "Invalid response", code: -1, userInfo: nil)))
                return
            }
            
            var transactions: [Transaction] = []
            
            for tx in txs.prefix(10) {
                if let time = tx["time"] as? TimeInterval,
                   let inputs = tx["inputs"] as? [[String: Any]],
                   let outputs = tx["out"] as? [[String: Any]],
                   let firstInput = inputs.first,
                   let prevOut = firstInput["prev_out"] as? [String: Any],
                   let fromAddr = prevOut["addr"] as? String,
                   let firstOutput = outputs.first,
                   let toAddr = firstOutput["addr"] as? String,
                   let value = firstOutput["value"] as? Int {
                    
                    let transaction = Transaction(
                        from: fromAddr,
                        to: toAddr,
                        amount: Double(value) / 100000000.0,
                        timestamp: Date(timeIntervalSince1970: time),
                        signature: nil
                    )
                    transactions.append(transaction)
                }
            }
            
            completion(.success(transactions))
        }.resume()
    }
}

